# Get unique prefixes from all source sheets
import re
for sn in ['CMSN', 'CSTR', 'EXPRO']:
    ws2 = wb[sn]
    prefixes = set()
    for r in range(2, ws2.max_row+1):
        ref = ws2.cell(r, 2).value
        if ref:
            # Extract prefix pattern
            if 'PUR PURCHASE' in ref:
                prefixes.add('PUR PURCHASE')
            elif 'PUR PAID' in ref:
                prefixes.add('PUR PAID')
            elif 'CASH SS' in ref:
                prefixes.add('CASH SS')
            elif 'EXPRR' in ref:
                prefixes.add('EXPRR')
            else:
                prefixes.add(ref[:20])
    print(f'{sn} prefixes: {prefixes}')
    print(f'{sn} row count: {ws2.max_row}')
